import React from 'react';
import { ShoppingCart, Bell } from 'lucide-react';

const NewProductsPage = () => {
  // Dados simulados dos produtos
  const newProducts = [
    { id: 1, name: "Camiseta Oversized", price: 129.90, image: "https://via.placeholder.com/200" },
    { id: 2, name: "Calça Cargo", price: 259.90, image: "https://via.placeholder.com/200" },
    { id: 3, name: "Moletom Graphic", price: 199.90, image: "https://via.placeholder.com/200" },
    { id: 4, name: "Tênis Urban", price: 399.90, image: "https://via.placeholder.com/200" },
  ];

  // Dados simulados das novidades
  const featuredNews = [
    {
      id: 1,
      title: "Nova Coleção Verão",
      description: "Descubra as últimas tendências em street wear para o verão.",
      image: "https://via.placeholder.com/400x200"
    },
    {
      id: 2,
      title: "Colaboração Exclusiva",
      description: "Uma parceria única com artistas urbanos locais.",
      image: "https://via.placeholder.com/400x200"
    },
    {
      id: 3,
      title: "Promoção Limitada",
      description: "Aproveite descontos especiais em peças selecionadas.",
      image: "https://via.placeholder.com/400x200"
    }
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div className="flex-1">
              <input
                type="search"
                placeholder="Pesquisar..."
                className="w-full max-w-xs px-4 py-2 rounded-lg border border-gray-300"
              />
            </div>
            <nav className="flex space-x-8">
              <a href="#" className="text-gray-600 hover:text-gray-900">LINK 1</a>
              <a href="#" className="text-gray-600 hover:text-gray-900">LINK 2</a>
              <a href="#" className="text-gray-600 hover:text-gray-900">WISHLIST</a>
            </nav>
            <div className="flex items-center space-x-4">
              <Bell className="h-6 w-6 text-gray-600 cursor-pointer" />
              <ShoppingCart className="h-6 w-6 text-gray-600 cursor-pointer" />
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8 text-center">Novos produtos</h1>

        {/* Products Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 mb-12">
          {newProducts.map((product) => (
            <div key={product.id} className="bg-white rounded-lg shadow-md overflow-hidden">
              <img
                src={product.image}
                alt={product.name}
                className="w-full h-48 object-cover"
              />
              <div className="p-4">
                <h3 className="font-medium text-gray-900">{product.name}</h3>
                <p className="text-lg font-bold text-gray-900 mt-1">
                  R$ {product.price.toFixed(2)}
                </p>
              </div>
            </div>
          ))}
        </div>

        {/* Featured News Section */}
        <div className="space-y-6">
          {featuredNews.map((news) => (
            <div key={news.id} className="bg-white rounded-lg shadow-md overflow-hidden">
              <div className="p-4">
                <div className="flex flex-col md:flex-row gap-6">
                  <img
                    src={news.image}
                    alt={news.title}
                    className="w-full md:w-1/3 h-48 object-cover rounded-lg"
                  />
                  <div className="flex-1">
                    <h2 className="text-xl font-bold text-gray-900 mb-2">{news.title}</h2>
                    <p className="text-gray-600">{news.description}</p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-gray-100 mt-12">
        <div className="max-w-7xl mx-auto px-4 py-8">
          <p className="text-center text-gray-600">© 2024 Street Wear Store. Todos os direitos reservados.</p>
        </div>
      </footer>
    </div>
  );
};

export default NewProductsPage;
